from flask import Blueprint, request, jsonify
from werkzeug.utils import secure_filename
import os

# Set up API endpoint for downloading invoices
invoices_blueprint = Blueprint('invoices', __name__, url_prefix='/api/invoices')

@invoices_blueprint.route('/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    # Assuming invoices are stored in a directory and named after their ID
    invoice_file_path = f'invoices/{invoice_id}.pdf'

    if os.path.exists(invoice_file_path):
        return send_file(invoice_file_path, as_attachment=True, attachment_filename=f'Invoice_{invoice_id}.pdf')
    else:
        return jsonify({'error': 'Invoice not found'}), 404

# Assuming the following function is defined elsewhere in your code
def send_file(path, **kwargs):
    from flask import send_from_directory
    return send_from_directory(os.path.dirname(path), os.path.basename(path), **kwargs)